mapper.select:
SELECT 'POST' AS itemType, cp.id AS postId, NULL AS commentId, NULL AS scrapId, cp.title AS title, LEFT(cp.content, 120) AS preview, NULL AS reactionType, cp.is_anonymous AS anonymous, cp.created_at AS createdAt FROM community_post cp WHERE cp.user_id = #{ownerId} AND cp.status = 'PUBLISHED'
AND cp.is_anonymous = 0
ORDER BY cp.created_at DESC, cp.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT 'REPLY''COMMENT' AS itemType, cc.post_id AS postId, cc.id AS commentId, NULL AS scrapId, cp.title AS title, LEFT(cc.content, 120) AS preview, NULL AS reactionType, cc.is_anonymous AS anonymous, cc.created_at AS createdAt FROM community_comment cc JOIN community_post cp ON cp.id = cc.post_id AND cp.status = 'PUBLISHED' WHERE cc.user_id = #{ownerId} AND cc.status = 'PUBLISHED' AND cc.parent_id IS NOT NULLNULL
AND cc.is_anonymous = 0
ORDER BY cc.created_at DESC, cc.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT * FROM ( SELECT 'POST' AS itemType, pr.post_id AS postId, NULL AS commentId, NULL AS scrapId, cp.title AS title, LEFT(cp.content, 120) AS preview, pr.reaction_type AS reactionType, pr.is_anonymous AS anonymous, pr.created_at AS createdAt FROM post_reaction pr JOIN community_post cp ON cp.id = pr.post_id AND cp.status = 'PUBLISHED' WHERE pr.user_id = #{ownerId} AND pr.reaction_type = 'LIKE'
AND pr.is_anonymous = 0
UNION ALL SELECT 'COMMENT' AS itemType, cc.post_id AS postId, cc.id AS commentId, NULL AS scrapId, cp2.title AS title, LEFT(cc.content, 120) AS preview, cr.reaction_type AS reactionType, cr.is_anonymous AS anonymous, cr.created_at AS createdAt FROM comment_reaction cr JOIN community_comment cc ON cc.id = cr.comment_id AND cc.status = 'PUBLISHED' JOIN community_post cp2 ON cp2.id = cc.post_id AND cp2.status = 'PUBLISHED' WHERE cr.user_id = #{ownerId} AND cr.reaction_type = 'LIKE'
AND cr.is_anonymous = 0
) liked ORDER BY liked.createdAt DESC LIMIT #{limit} OFFSET #{offset}

SELECT ( SELECT COUNT(*) FROM post_reaction pr JOIN community_post cp ON cp.id = pr.post_id AND cp.status = 'PUBLISHED' WHERE pr.user_id = #{ownerId} AND pr.reaction_type = 'LIKE'
AND pr.is_anonymous = 0
) + ( SELECT COUNT(*) FROM comment_reaction cr JOIN community_comment cc ON cc.id = cr.comment_id AND cc.status = 'PUBLISHED' JOIN community_post cp2 ON cp2.id = cc.post_id AND cp2.status = 'PUBLISHED' WHERE cr.user_id = #{ownerId} AND cr.reaction_type = 'LIKE'
AND cr.is_anonymous = 0
)

SELECT 'POST' AS itemType, pr.post_id AS postId, NULL AS commentId, NULL AS scrapId, cp.title AS title, LEFT(cp.content, 120) AS preview, pr.reaction_type AS reactionType, pr.is_anonymous AS anonymous, pr.created_at AS createdAt FROM post_reaction pr JOIN community_post cp ON cp.id = pr.post_id AND cp.status = 'PUBLISHED' WHERE pr.user_id = #{ownerId} AND pr.reaction_type = 'BOOKMARK'
AND pr.is_anonymous = 0
ORDER BY pr.created_at DESC, pr.id DESC LIMIT #{limit} OFFSET #{offset}

SELECT 'SCRAP' AS itemType, ps.post_id AS postId, NULL AS commentId, ps.id AS scrapId, ps.snapshot_title AS title, LEFT(ps.snapshot_content, 120) AS preview, NULL AS reactionType, ps.is_anonymous AS anonymous, ps.scrapped_at AS createdAt FROM post_scrap ps WHERE ps.user_id = #{ownerId}
AND ps.is_anonymous = 0
ORDER BY ps.scrapped_at DESC, ps.id DESC LIMIT #{limit} OFFSET #{offset}
